import os
import hashlib
import hmac
from functools import wraps
from flask import Flask, session, request, redirect, url_for, render_template_string, flash
from datetime import datetime, timedelta

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', os.urandom(24))
app.config['PERMANENT_SESSION_LIFETIME'] = timedelta(days=7)

users_db = {}

def hash_password(password, salt=None):
    if salt is None:
        salt = os.urandom(32)
    pwd_hash = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt, 100000)
    return salt + pwd_hash

def verify_password(stored_password, provided_password):
    salt = stored_password[:32]
    stored_hash = stored_password[32:]
    pwd_hash = hashlib.pbkdf2_hmac('sha256', provided_password.encode('utf-8'), salt, 100000)
    return hmac.compare_digest(stored_hash, pwd_hash)

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function

@app.route('/')
def index():
    if 'user_id' in session:
        username = session.get('username')
        return render_template_string('''
            <!DOCTYPE html>
            <html>
            <head><title>Home</title></head>
            <body>
                <h1>Welcome, {{ username }}!</h1>
                <p>You are logged in.</p>
                <a href="{{ url_for('dashboard') }}">Go to Dashboard</a><br>
                <a href="{{ url_for('logout') }}">Logout</a>
            </body>
            </html>
        ''', username=username)
    return render_template_string('''
        <!DOCTYPE html>
        <html>
        <head><title>Home</title></head>
        <body>
            <h1>Welcome to Session Management System</h1>
            <a href="{{ url_for('login') }}">Login</a><br>
            <a href="{{ url_for('register') }}">Register</a>
        </body>
        </html>
    ''')

@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        
        if not username or not password:
            flash('Username and password are required')
            return redirect(url_for('register'))
        
        if username in users_db:
            flash('Username already exists')
            return redirect(url_for('register'))
        
        users_db[username] = {
            'password': hash_password(password),
            'created_at': datetime.now()
        }
        
        flash('Registration successful! Please login.')
        return redirect(url_for('login'))
    
    return render_template_string('''
        <!DOCTYPE html>
        <html>
        <head><title>Register</title></head>
        <body>
            <h1>Register</h1>
            {% with messages = get_flashed_messages() %}
                {% if messages %}
                    {% for message in messages %}
                        <p style="color: red;">{{ message }}</p>
                    {% endfor %}
                {% endif %}
            {% endwith %}
            <form method="post">
                <label>Username: <input type="text" name="username" required></label><br>
                <label>Password: <input type="password" name="password" required></label><br>
                <button type="submit">Register</button>
            </form>
            <a href="{{ url_for('login') }}">Already have an account? Login</a>
        </body>
        </html>
    ''')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        remember = request.form.get('remember')
        
        if not username or not password:
            flash('Username and password are required')
            return redirect(url_for('login'))
        
        user = users_db.get(username)
        
        if user and verify_password(user['password'], password):
            session.clear()
            session['user_id'] = username
            session['username'] = username
            session['login_time'] = datetime.now().isoformat()
            
            if remember:
                session.permanent = True
            else:
                session.permanent = False
            
            flash('Login successful!')
            return redirect(url_for('dashboard'))
        else:
            flash('Invalid username or password')
            return redirect(url_for('login'))
    
    return render_template_string('''
        <!DOCTYPE html>
        <html>
        <head><title>Login</title></head>
        <body>
            <h1>Login</h1>
            {% with messages = get_flashed_messages() %}
                {% if messages %}
                    {% for message in messages %}
                        <p style="color: red;">{{ message }}</p>
                    {% endfor %}
                {% endif %}
            {% endwith %}
            <form method="post">
                <label>Username: <input type="text" name="username" required></label><br>
                <label>Password: <input type="password" name="password" required></label><br>
                <label><input type="checkbox" name="remember" value="1"> Remember me</label><br>
                <button type="submit">Login</button>
            </form>
            <a href="{{ url_for('register') }}">Don't have an account? Register</a>
        </body>
        </html>
    ''')

@app.route('/dashboard')
@login_required
def dashboard():
    username = session.get('username')
    login_time = session.get('login_time')
    is_permanent = session.permanent
    
    return render_template_string('''
        <!DOCTYPE html>
        <html>
        <head><title>Dashboard</title></head>
        <body>
            <h1>Dashboard</h1>
            <p>Username: {{ username }}</p>
            <p>Login Time: {{ login_time }}</p>
            <p>Session Type: {{ 'Permanent (Remember Me)' if is_permanent else 'Temporary' }}</p>
            <a href="{{ url_for('index') }}">Home</a><br>
            <a href="{{ url_for('logout') }}">Logout</a>
        </body>
        </html>
    ''', username=username, login_time=login_time, is_permanent=is_permanent)

@app.route('/logout')
def logout():
    session.clear()
    flash('You have been logged out.')
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True)